function decodeRecording(rec) {
  const N = 10, stride = N * 2 + 1;
  const frames = [];
  const d = rec.data;
  for (let i = 0; i < d.length; i += stride) {
    const balls = [];
    for (let j = 0; j < N; j++) {
      balls.push({ id: j, x: d[i + 1 + j*2], y: d[i + 2 + j*2] });
    }
    frames.push({ t: d[i], balls });
  }
  return { name: rec.name, duration: rec.dur, frames };
}

const RECORDINGS = RECORDING_DATA.map(decodeRecording);
